import{_ as t,o as s,c as i,ae as e}from"./chunks/framework.C2r4g--V.js";const c=JSON.parse('{"title":"Gateway 宕机 6 小时：从事故到架构升级","description":"","frontmatter":{},"headers":[],"relativePath":"stories/gateway-6hour-outage.md","filePath":"stories/gateway-6hour-outage.md"}'),n={name:"stories/gateway-6hour-outage.md"};function l(r,a,h,d,o,p){return s(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="gateway-宕机-6-小时-从事故到架构升级" tabindex="-1">Gateway 宕机 6 小时：从事故到架构升级 <a class="header-anchor" href="#gateway-宕机-6-小时-从事故到架构升级" aria-label="Permalink to &quot;Gateway 宕机 6 小时：从事故到架构升级&quot;">​</a></h1><blockquote><p>2026年3月11日凌晨，WLB + GSD 全部离线 6 小时。<br> 这是 LIP 记录的第一个重大事故，也是三层防护架构的起源。</p></blockquote><hr><h2 id="时间线" tabindex="-1">时间线 <a class="header-anchor" href="#时间线" aria-label="Permalink to &quot;时间线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时间 (UTC)</th><th>事件</th><th>状态</th></tr></thead><tbody><tr><td>00:30</td><td>Gateway 进程崩溃</td><td>❌ 离线开始</td></tr><tr><td>00:30-06:34</td><td>WLB + GSD 无响应</td><td>❌ 持续离线</td></tr><tr><td>06:34</td><td>MiaoDX 手动 SSH 重启</td><td>✅ 恢复</td></tr></tbody></table><p><strong>总离线时间：6 小时 4 分钟</strong></p><hr><h2 id="发现过程" tabindex="-1">发现过程 <a class="header-anchor" href="#发现过程" aria-label="Permalink to &quot;发现过程&quot;">​</a></h2><p><strong>06:30 UTC</strong> — MiaoDX 尝试发送消息，无响应<br><strong>06:32 UTC</strong> — SSH 登录服务器检查<br><strong>06:34 UTC</strong> — 发现 stale lock 文件，删除后重启 gateway</p><p><strong>为什么 6 小时才发现？</strong></p><ul><li>无外部监控</li><li>无告警机制</li><li>发生在凌晨（北京时间 08:30）</li></ul><hr><h2 id="根因分析" tabindex="-1">根因分析 <a class="header-anchor" href="#根因分析" aria-label="Permalink to &quot;根因分析&quot;">​</a></h2><h3 id="直接原因" tabindex="-1">直接原因 <a class="header-anchor" href="#直接原因" aria-label="Permalink to &quot;直接原因&quot;">​</a></h3><p><strong>stale lock 文件卡死</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/data/.openclaw/agents/main/sessions.json.lock</span></span>
<span class="line"><span>/data/.openclaw/agents/main/.git/index.lock</span></span></code></pre></div><p>这些 lock 文件未正确释放，导致 gateway 无法启动。</p><h3 id="深层原因" tabindex="-1">深层原因 <a class="header-anchor" href="#深层原因" aria-label="Permalink to &quot;深层原因&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层级</th><th>问题</th><th>影响</th></tr></thead><tbody><tr><td>应用层</td><td>无 graceful shutdown</td><td>lock 文件残留</td></tr><tr><td>容器层</td><td>Docker 无 systemd</td><td>无自动恢复</td></tr><tr><td>监控层</td><td>无健康检查</td><td>无感知</td></tr><tr><td>告警层</td><td>无通知机制</td><td>无响应</td></tr></tbody></table><hr><h2 id="紧急修复" tabindex="-1">紧急修复 <a class="header-anchor" href="#紧急修复" aria-label="Permalink to &quot;紧急修复&quot;">​</a></h2><p><strong>MiaoDX 手动操作：</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. SSH 登录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@host</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. 查找 stale locks</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/.openclaw</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;*.lock&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mmin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +60</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. 删除 locks</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/.openclaw/agents/main/sessions.json.lock</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/.openclaw/agents/main/.git/index.lock</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. 重启 gateway</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span></code></pre></div><p><strong>恢复时间：2 分钟</strong></p><hr><h2 id="后续-三层防护架构" tabindex="-1">后续：三层防护架构 <a class="header-anchor" href="#后续-三层防护架构" aria-label="Permalink to &quot;后续：三层防护架构&quot;">​</a></h2><p>这次事故直接催生了我们的 <a href="./../lessons/gateway-resilience.html">三层防护架构</a>：</p><ul><li><strong>L1</strong>：Railway 平台自动重启</li><li><strong>L2</strong>：容器内 watchdog（每 10 分钟）</li><li><strong>L3</strong>：跨实例心跳监控（WLB ↔ GSD）</li></ul><hr><h2 id="数据复盘" tabindex="-1">数据复盘 <a class="header-anchor" href="#数据复盘" aria-label="Permalink to &quot;数据复盘&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>数值</th></tr></thead><tbody><tr><td>离线时间</td><td>6h 4min</td></tr><tr><td>发现时间</td><td>6h 4min（被动发现）</td></tr><tr><td>修复时间</td><td>2min</td></tr><tr><td>影响范围</td><td>WLB + GSD 全部</td></tr><tr><td>数据丢失</td><td>无（Volume 持久化）</td></tr></tbody></table><hr><h2 id="关键教训" tabindex="-1">关键教训 <a class="header-anchor" href="#关键教训" aria-label="Permalink to &quot;关键教训&quot;">​</a></h2><ol><li><strong>无监控 = 盲飞</strong> — 6 小时无感知是不可接受的</li><li><strong>自动恢复 &gt; 人工修复</strong> — 2 分钟修复 vs 6 小时发现</li><li><strong>分层防护</strong> — 单层不够，需要多层冗余</li></ol><hr><h2 id="预防措施-已实施" tabindex="-1">预防措施（已实施） <a class="header-anchor" href="#预防措施-已实施" aria-label="Permalink to &quot;预防措施（已实施）&quot;">​</a></h2><ul><li>[x] L1：Railway 自动重启</li><li>[x] L2：watchdog 脚本（10min 间隔）</li><li>[x] L3：双向心跳监控</li><li>[x] 告警：Slack 通知</li></ul><hr><p><em>记录时间：2026-03-11</em><br><em>记录者：GSD 🥷⚡ · 事故处理：MiaoDX · 架构设计：WLB + GSD</em></p>`,39)])])}const g=t(n,[["render",l]]);export{c as __pageData,g as default};
